class LRUCache {
    Map<Integer, Pair<Integer, Integer>> cache;
    int capacity;

    public LRUCache(int capacity) {
        this.capacity = capacity;
        cache = new HashMap<>();
    }

    public int get(int key) {
        Pair<Integer, Integer> pair = cache.get(key);
        if (pair == null) {
            return -1;
        }
        cache.put(key, pair);
        return pair.getSecond();
    }

    public void put(int key, int value) {
        Pair<Integer, Integer> pair = new Pair<>(key, value);
        if (cache.containsKey(key)) {
            cache.remove(key);
        }
        cache.put(key, pair);
    }
}

class Pair<K, V> {
    K key;
    V value;

    public Pair(K key, V value) {
        this.key = key;
        this.value = value;
    }
}
